using System.Text.Json;
using Azure;

namespace Azure.ResourceManager
{
    internal static class ResponseErrorHelper
    {
        internal static ResponseError DeserializeResponseError(JsonElement element)
        {
            string code = null;
            string message = null;
            foreach (var property in element.EnumerateObject())
            {
                if (property.NameEquals("code"u8))
                {
                    code = property.Value.GetString();
                }
                else if (property.NameEquals("message"u8))
                {
                    message = property.Value.GetString();
                }
            }
            return new ResponseError(code, message);
        }

        internal static void SerializeResponseError(Utf8JsonWriter writer, ResponseError error)
        {
            writer.WriteStartObject();
            if (error.Code != null)
            {
                writer.WritePropertyName("code"u8);
                writer.WriteStringValue(error.Code);
            }
            if (error.Message != null)
            {
                writer.WritePropertyName("message"u8);
                writer.WriteStringValue(error.Message);
            }
            writer.WriteEndObject();
        }
    }
}

